  ('dietitian-moex-01910', 'dietitian', 'dietitian-moex-107-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '根據現行勞動基準法，子女未滿 1 歲需母親親自哺乳者，於規定之休息時間外，雇主應每日另給予幾次 哺乳時間？', '["1", "2", "3", "4"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:57+00:00", "source_pdf_sha1": "0bfeb6891da2", "answer_pdf_sha1": "563ab781ede4", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "103", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公共衛生營養學", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
