  ('dietitian-moex-01912', 'dietitian', 'dietitian-moex-107-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '某國中營養師設計給學生之午餐內容為：五穀飯1碗、無骨滷豬排（105公克）、胡蘿蔔（50公克）炒 半顆蛋、炒油菜（100公克）、冬瓜湯（冬瓜10公克＋薑絲少許）、香蕉1根（55公克），則下列敘述 何者正確？', '["全穀根莖類份量剛好", "豆魚肉蛋類份量應減少", "蔬菜類份量太多", "水果份量太多"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:57+00:00", "source_pdf_sha1": "0bfeb6891da2", "answer_pdf_sha1": "563ab781ede4", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "103", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公共衛生營養學", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL)
